-- ================================================================
-- NaviTour: Station Migration v2 (agency_id fixed)
-- SAFE ORDER:
--   1. Patch app.py + scoring.py first (see patch files)
--   2. Then run this SQL
-- ================================================================

BEGIN;

DROP TABLE IF EXISTS stations CASCADE;
DROP TABLE IF EXISTS metro_stations CASCADE;
DROP TABLE IF EXISTS bus_stops CASCADE;

CREATE TABLE metro_stations (
    station_id     SERIAL PRIMARY KEY,
    name_ar        TEXT NOT NULL,
    name_en        TEXT NOT NULL,
    name_ar_norm   TEXT NOT NULL,
    line           TEXT NOT NULL,          -- L1 or L2
    seq            INTEGER NOT NULL,       -- station order on line
    gtfs_stop_id   TEXT NOT NULL,          -- for RAPTOR
    is_interchange BOOLEAN DEFAULT FALSE,  -- Sadat, Al-Shohadaa
    geom           geography(Point,4326)
);

CREATE INDEX idx_metro_stations_geom ON metro_stations USING GIST(geom);
CREATE INDEX idx_metro_stations_name_ar ON metro_stations(name_ar);
CREATE INDEX idx_metro_stations_norm ON metro_stations(name_ar_norm);
CREATE INDEX idx_metro_stations_line ON metro_stations(line, seq);


SELECT setval('metro_stations_station_id_seq',(SELECT MAX(station_id) FROM metro_stations));

CREATE TABLE bus_stops (
    stop_id      INTEGER PRIMARY KEY,
    name_en      TEXT NOT NULL,
    name_ar      TEXT,
    name_ar_norm TEXT,
    agency_id    TEXT,                 -- CTA / P_O_14 / CTA_M / P_B_8 / COOP / MM / BOX / GRN
    near_metro   INTEGER REFERENCES metro_stations(station_id),
    near_dist_m  INTEGER,
    geom         geography(Point,4326)
);

CREATE INDEX idx_bus_stops_geom    ON bus_stops USING GIST(geom);
CREATE INDEX idx_bus_stops_name_ar ON bus_stops(name_ar);
CREATE INDEX idx_bus_stops_norm    ON bus_stops(name_ar_norm);
CREATE INDEX idx_bus_stops_agency  ON bus_stops(agency_id);
CREATE INDEX idx_bus_stops_near    ON bus_stops(near_metro);


-- Link bus stops to nearest metro station within 250m
UPDATE bus_stops b
SET near_metro  = m.station_id,
    near_dist_m = ROUND(m.dist)::INTEGER
FROM (
    SELECT DISTINCT ON (b2.stop_id)
           b2.stop_id,
           m2.station_id,
           ST_Distance(b2.geom, m2.geom) AS dist
    FROM   bus_stops b2
    JOIN   metro_stations m2 
           ON ST_DWithin(b2.geom, m2.geom, 250)
    ORDER  BY b2.stop_id, dist
) m
WHERE b.stop_id = m.stop_id;
COMMIT;

-- ── Verify ──────────────────────────────────────────────────────
SELECT 'metro_stations' AS tbl, COUNT(*) FROM metro_stations
UNION ALL SELECT 'bus_stops',   COUNT(*) FROM bus_stops
UNION ALL SELECT 'transfer_stops (near_metro set)', COUNT(*) FROM bus_stops WHERE near_metro IS NOT NULL;
SELECT line, COUNT(*) FROM metro_stations GROUP BY line ORDER BY line;
SELECT agency_id, COUNT(*) FROM bus_stops GROUP BY agency_id ORDER BY COUNT(*) DESC;